{
    "18.3.7. Receipt of Release Messages": [
        {
            "Original": "SeeSection 18.4 for details regarding the handling of Release messages received via unicast.",
            "Adjusted": "See Section 18.4 for details regarding the handling of Release messages received via unicast."
        },
        {
            "Original": "The server constructs a Reply message by setting the \"msg-type\" field to REPLY and copying the transaction ID from the Release message into the \"transaction-id\" field.",
            "Adjusted": "No change"
        },
        {
            "Original": "Upon the receipt of a valid Release message, the server examines the IAs and the leases in the IAs for validity.",
            "Adjusted": "No change"
        },
        {
            "Original": "If the IAs in the message are in a binding for the client and the leases in the IAs have been assigned by the server to those IAs, the server deletes the leases from the IAs and makes the leases available for assignment to other clients.",
